import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import { FiPlus, FiCheck, FiX } from 'react-icons/fi';

const LeaveRequests = () => {
  const [requests, setRequests] = useState([]);
  const [employees, setEmployees] = useState([]);
  const [leaveTypes, setLeaveTypes] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState({ employee: '', leaveType: '', fromDate: '', toDate: '', reason: '' });

  useEffect(() => {
    fetchRequests();
    api.get('/pim/employees').then(res => setEmployees(res.data)).catch(() => {});
    api.get('/leave/types').then(res => setLeaveTypes(res.data)).catch(() => {});
  }, []);

  const fetchRequests = async () => {
    const { data } = await api.get('/leave/requests');
    setRequests(data);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    await api.post('/leave/requests', form);
    setShowModal(false);
    setForm({ employee: '', leaveType: '', fromDate: '', toDate: '', reason: '' });
    fetchRequests();
  };

  const handleApprove = async (id) => {
    await api.put(`/leave/approve/${id}`);
    fetchRequests();
  };

  const handleReject = async (id) => {
    await api.put(`/leave/reject/${id}`);
    fetchRequests();
  };

  return (
    <div>
      <div className="toolbar">
        <div className="toolbar-right" style={{ marginLeft: 'auto' }}>
          <button className="btn btn-primary" onClick={() => setShowModal(true)}><FiPlus /> Apply Leave</button>
        </div>
      </div>
      <div className="card">
        <div className="card-header"><h3>Leave Requests</h3></div>
        <div className="card-body">
          <div className="table-container">
            <table>
              <thead><tr><th>Employee</th><th>Leave Type</th><th>From</th><th>To</th><th>Days</th><th>Status</th><th>Actions</th></tr></thead>
              <tbody>
                {requests.map(r => (
                  <tr key={r._id}>
                    <td><strong>{r.employee?.fullName}</strong></td>
                    <td>{r.leaveType?.name || '-'}</td>
                    <td>{new Date(r.fromDate).toLocaleDateString()}</td>
                    <td>{new Date(r.toDate).toLocaleDateString()}</td>
                    <td>{r.numberOfDays}</td>
                    <td><span className={`status-badge status-${r.status}`}>{r.status}</span></td>
                    <td>
                      {r.status === 'pending' && (
                        <>
                          <button className="action-btn" style={{ color: '#2ecc71' }} onClick={() => handleApprove(r._id)} title="Approve"><FiCheck /></button>
                          <button className="action-btn" style={{ color: '#e74c3c' }} onClick={() => handleReject(r._id)} title="Reject"><FiX /></button>
                        </>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
      {showModal && (
        <div className="modal-backdrop" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header"><h3>Apply Leave</h3><button className="close-btn" onClick={() => setShowModal(false)}>&times;</button></div>
            <form onSubmit={handleSubmit}>
              <div className="modal-body">
                <div className="form-group"><label>Employee</label><select value={form.employee} onChange={e => setForm({...form, employee: e.target.value})} required>
                  <option value="">Select...</option>
                  {employees.map(e => <option key={e._id} value={e._id}>{e.fullName}</option>)}
                </select></div>
                <div className="form-group"><label>Leave Type</label><select value={form.leaveType} onChange={e => setForm({...form, leaveType: e.target.value})} required>
                  <option value="">Select...</option>
                  {leaveTypes.map(lt => <option key={lt._id} value={lt._id}>{lt.name}</option>)}
                </select></div>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
                  <div className="form-group"><label>From Date</label><input type="date" value={form.fromDate} onChange={e => setForm({...form, fromDate: e.target.value})} required /></div>
                  <div className="form-group"><label>To Date</label><input type="date" value={form.toDate} onChange={e => setForm({...form, toDate: e.target.value})} required /></div>
                </div>
                <div className="form-group"><label>Reason</label><textarea value={form.reason} onChange={e => setForm({...form, reason: e.target.value})} rows={2} /></div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-outline" onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary">Apply</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default LeaveRequests;
